#!/usr/bin/env bash
set -euo pipefail
_CLI_B64=''

INSTALL_DIR="${1:-$HOME/.local/bin}"
APP_DIR="$HOME/.myqodercli"

if ! command -v node &>/dev/null; then
  echo "error: Node.js >= 18 required" >&2
  exit 1
fi
if [ "$(node -e 'console.log(parseInt(process.versions.node))')" -lt 18 ]; then
  echo "error: Node.js >= 18 required (found: $(node -v))" >&2
  exit 1
fi

mkdir -p "$APP_DIR"

cat > "$APP_DIR/package.json" <<'PKG'
{"dependencies":{"node-pty":"^1.1.0"}}
PKG

cd "$APP_DIR"
npm install --production --silent 2>/dev/null || npm install --production 2>&1 | tail -1

echo "$_CLI_B64" | base64 -d > "$APP_DIR/cli.cjs"
# If base64 decoded file seems broken, try fetching fresh from Gitee/GitHub
if ! node -c "$APP_DIR/cli.cjs" 2>/dev/null; then
  for url in \
    "https://gitee.com/ranxianglei/myqodercli/raw/master/dist/bin/cli.cjs" \
    "https://ghproxy.com/https://raw.githubusercontent.com/ranxianglei/myqodercli/master/dist/bin/cli.cjs" \
    "https://raw.githubusercontent.com/ranxianglei/myqodercli/master/dist/bin/cli.cjs"; do
    if command -v curl &>/dev/null; then
      curl -fsSL "$url" -o "$APP_DIR/cli.cjs" 2>/dev/null && break
    elif command -v wget &>/dev/null; then
      wget -qO "$APP_DIR/cli.cjs" "$url" 2>/dev/null && break
    fi
  done
fi

mkdir -p "$INSTALL_DIR"
REAL_APP_DIR="$(cd "$APP_DIR" && pwd)"
cat > "$INSTALL_DIR/myqodercli" <<WEOF
#!/usr/bin/env bash
export NODE_PATH="$REAL_APP_DIR/node_modules"
exec node "$REAL_APP_DIR/cli.cjs" "\$@"
WEOF

chmod +x "$INSTALL_DIR/myqodercli"

echo "myqodercli installed -> $INSTALL_DIR/myqodercli"
echo ""
echo "usage:"
echo "  myqodercli                           # auto-yolo (TUI)"
echo "  myqodercli -w /path/to/project       # auto-yolo"
echo "  myqodercli -p 'explain this code'    # non-interactive"
echo "  myqodercli --no-yolo -w /path        # require permissions"
echo "  myqodercli --continue                # resume conversation"
